// 用 div 包住：多一層跟語意無關的節點，也可能打斷 CSS 直接子元素選擇器（如 .list > *）
function Item({ label }) {
  return (
    <div>
      <dt>{label}</dt>
      <dd>說明文字</dd>
    </div>
  );
}

// 改用 Fragment：不產生任何額外節點
function Item({ label }) {
  return (
    <>
      <dt>{label}</dt>
      <dd>說明文字</dd>
    </>
  );
}

function Modal({ children }) {
  return ReactDOM.createPortal(
    <div className="modal">{children}</div>,
    document.getElementById("modal-root")
  );
}

function Greeting({ name }) {
  return <p>Hello, {name}</p>; // 沒有 state，畫面完全由 props 決定
}

function Counter() {
  const [count, setCount] = useState(0); // 有自己的內部記憶
  return <button onClick={() => setCount(count + 1)}>{count}</button>;
}

